INSERT INTO public.clientes (nombre, email, telefono, ciudad, estado, origen, estado_contacto, descripcion, ref_cliente, mensaje, fecha_contacto, notas, tipo_operacion) VALUES ('albert ribas', 'albertriru@gmail.com', NULL, NULL, 'pendiente', 'otro', NULL, 'Ático en venta en Avenida de Madrid', '515k 2h 80m Avenida Madrid', 'Hola,

He tingut coneixement que COCONUT LUXURY FLATS està comercialitzant i publicitant el meu habitatge a través d’Idealista sense disposar de cap mandat, encàrrec ni autorització per fer-ho.

No he autoritzat la vostra empresa a oferir l’immoble al mercat, utilitzar les seves fotografies ni captar potencials compradors a través d’aquest.

La utilització d’un immoble aliè com si formés part de la vostra cartera comercial constitueix una actuació absolutament inadmissible i de la qual ja he deixat constància documental.

Us requereixo perquè retireu l’anunci de forma immediata i em confirmeu per escrit la seva eliminació, així com perquè m’informeu de la identitat de la persona que us ha facilitat les fotografies i la informació utilitzades per a la seva publicació.

En cas contrari, em reservo expressament l’exercici de quantes accions em corresponguin en defensa dels meus drets i interessos.', '2026-08-06T09:39:20.000Z', NULL, 'venta');
