INSERT INTO public.clientes (nombre, email, telefono, ciudad, estado, origen, estado_contacto, descripcion, ref_cliente, mensaje, fecha_contacto, notas, tipo_operacion) VALUES ('Fernanda', 'fernanda.bortolosso@gmail.com', '711 05 43 07', NULL, 'pendiente', 'otro', NULL, 'Piso en venta en Calle Ample, 23', 'ESP 235K 2H Ample Gotico', 'Hola, buenos días. Le escribo por el anuncio del piso en 235K 2H Ample gotico, sigue disponible?

