INSERT INTO public.clientes (nombre, email, telefono, ciudad, estado, origen, estado_contacto, descripcion, ref_cliente, mensaje, fecha_contacto, notas, tipo_operacion) VALUES ('Sergi Huertas Galiana', 'sergi.huertas@goroka.tv', NULL, NULL, 'pendiente', 'otro', NULL, 'Oficina en venta en Ronda de Sant Pere', '895k 265m Ronda Sant Pere Dreta Eixample Eixample', 'Hola, contactamos desde Goroka Contents, productora de Barcelona porque estamos buscando una oficina para hacer dos jornadas de rodaje entre el 24 de noviembre y el 5 de diciembre. Seria un rodaje sencillo con poco material y un equipo de unas 4 o 5 personas como mucho, desde primera hora (8h-9h) hasta por la tarde (18h-19h) como mucho. Al ser un proyecto nuevo no contamos con un presupuesto amplio y podemos destinar un total de 100€ por jornada. Solemos buscar en este tipo de anuncios de alquiler ya que si el inmueble está libre, el propietario puede sacar rendimiento, aunque sean pocas jornadas, haciendo un contrato de localización para esos días en concreto, por eso me gustaría saber si hay disponibilidad y si existe la posibilidad de llevar a cabo este rodaje para buscar una fecha previa para visitar el espacio.

Quedo a la espera de su respuesta.

Muchas gracias.', '2025-05-11T09:09:54.000Z', NULL, 'venta');
