INSERT INTO public.clientes (nombre, email, telefono, ciudad, estado, origen, estado_contacto, descripcion, ref_cliente, mensaje, fecha_contacto, notas, tipo_operacion) VALUES ('Jorge', 'jorge.fdz.santos@gmail.com', '888 88 88 88', NULL, 'pendiente', 'otro', NULL, 'Piso en venta en Calle de València', 'ES 390k 3h 80m Valencia Sagrada Familia Eixample', 'Hola, me interesa este piso en Calle Valencia (podéis acotar un poco más la zona?). Entiendo que el piso SE ENTREGARÁ TOTALMENTE REFORMADO, como nuevo con materiales de alta calidad, debido al precio anunciado estratosférico, y a la descripción donde pone que es un piso ESPECTACULAR, lo cual no se corresponde con las imágenes mostradas. Así mismo, vuestra agencia se anuncia como LUXURY y este piso es de la época de “Cuéntame cómo pasó” nada lujoso. Los 4.600€/m2 la verdad que no se como se han tasado, pero por su estado no debería superar los 2.500€/m2 ya que necesita una reforma integral.
Me guardo el piso porque sé que tiene una fuerte caída por delante. Si la propiedad está abierta a una fuerte y necesaria corrección en el precio podemos agendar una visita para verlo, y hablar de los gastos de comunidad, IBI, derramas pendientes, adecuación del ascensor a la nueva normativa, sistemas de aislamiento del edificio, vecinos morosos, pisos con licencia turística y de corta duración, etc.
Quedo a la espera de sus noticias,
Jorge', NULL, NULL, 'venta');
